// Merge Gmail + Calendar data into a single brief context
const emailItems = $('Gmail — Get Today Emails').all();
const calendarItems = $('Calendar — Get Today Events').all();

// Process emails
const emails = emailItems.map(item => {
  const msg = item.json;
  const headers = msg.payload?.headers || [];
  const subject = headers.find(h => h.name === 'Subject')?.value || '(Sin asunto)';
  const from = headers.find(h => h.name === 'From')?.value || 'Desconocido';
  const date = headers.find(h => h.name === 'Date')?.value || '';
  const isImportant = (msg.labelIds || []).includes('IMPORTANT');
  const isUnread = (msg.labelIds || []).includes('UNREAD');

  return {
    subject,
    from,
    date,
    isImportant,
    isUnread,
    snippet: msg.snippet || ''
  };
});

// Process calendar events
const events = calendarItems.map(item => {
  const ev = item.json;
  return {
    summary: ev.summary || '(Sin título)',
    start: ev.start?.dateTime || ev.start?.date || '',
    end: ev.end?.dateTime || ev.end?.date || '',
    location: ev.location || '',
    description: ev.description || '',
    attendees: (ev.attendees || []).map(a => a.email).join(', ')
  };
});

// Format today's date in Guatemala (UTC-6)
const now = new Date();
const gtOffset = -6 * 60;
const gtTime = new Date(now.getTime() + gtOffset * 60000);
const dateStr = gtTime.toLocaleDateString('es-GT', { 
  weekday: 'long', 
  year: 'numeric', 
  month: 'long', 
  day: 'numeric',
  timeZone: 'UTC'
});

// Build prompt context
const emailContext = emails.length > 0
  ? emails.map((e, i) => 
      `${i+1}. ${e.isImportant ? '[IMPORTANTE] ' : ''}${e.isUnread ? '[NO LEÍDO] ' : ''}\n   De: ${e.from}\n   Asunto: ${e.subject}\n   Preview: ${e.snippet}`
    ).join('\n\n')
  : 'No hay correos nuevos o importantes en las últimas 24 horas.';

const calendarContext = events.length > 0
  ? events.map((e, i) => {
      const startTime = e.start ? new Date(e.start).toLocaleTimeString('es-GT', {hour: '2-digit', minute: '2-digit', timeZone: 'UTC'}) : 'Todo el día';
      const endTime = e.end ? new Date(e.end).toLocaleTimeString('es-GT', {hour: '2-digit', minute: '2-digit', timeZone: 'UTC'}) : '';
      return `${i+1}. ${e.summary}\n   Hora: ${startTime}${endTime ? ' - ' + endTime : ''}\n   ${e.location ? 'Lugar: ' + e.location : ''}\n   ${e.attendees ? 'Participantes: ' + e.attendees : ''}`;
    }).join('\n\n')
  : 'No tienes reuniones programadas para hoy.';

return [{
  json: {
    date: dateStr,
    emailContext,
    calendarContext,
    emailCount: emails.length,
    eventCount: events.length
  }
}];

